def _slice(text: str, start_re: str, end_re: str) -> str:
    lines = text.splitlines()
    start_pat = re.compile(start_re)
    end_pat = re.compile(end_re)
    start_idx = None
    for i, ln in enumerate(lines):
        if start_pat.search(ln):
            start_idx = i
            break
    assert start_idx is not None, f"start anchor {start_re!r} not found"
    for j in range(start_idx + 1, len(lines)):
        if end_pat.search(lines[j]):
            return "\n".join(lines[start_idx:j])
    return "\n".join(lines[start_idx:])


